	"sync"
	"time"
)

// Copied implementation for testing
type DurationTracker struct {
	mu        sync.RWMutex
	durations []time.Duration
}

func (dt *DurationTracker) Record(d time.Duration) {
	dt.mu.Lock()
	defer dt.mu.Unlock()
	dt.durations = append(dt.durations, d)
}

func (dt *DurationTracker) Stats() (count int, avg time.Duration, p99 time.Duration) {
	dt.mu.RLock()
	defer dt.mu.RUnlock()

	count = len(dt.durations)
	if count == 0 {
		return 0, 0, 0
	}

	var sum time.Duration
	for _, d := range dt.durations {
		sum += d
	}
	avg = sum / time.Duration(count)

	sorted := make([]time.Duration, count)
	copy(sorted, dt.durations)

	// Sort manually (simplified)
	for i := 0; i < count; i++ {
		for j := i + 1; j < count; j++ {
			if sorted[j] < sorted[i] {
				sorted[i], sorted[j] = sorted[j], sorted[i]
			}
		}
	}

	p99Index := (99 * count) / 100
	if p99Index >= count {
		p99Index = count - 1
	}
	p99 = sorted[p99Index]

	return count, avg, p99
}

func main() {
	dt := &DurationTracker{}

	// Record some durations
	for i := 0; i < 100; i++ {
		dt.Record(time.Duration(i*100) * time.Microsecond)
	}

	count, avg, p99 := dt.Stats()
	fmt.Printf("Count: %d\n", count)
	fmt.Printf("Average: %v\n", avg)
	fmt.Printf("P99: %v\n", p99)
	fmt.Println("\nDurationTracker is thread-safe and functional!")
}
EOF
